// SPDX-License-Identifier: ISC
//! Replay of frozen go-flags front-end vectors generated by a
//! package-main dump test at release-v2.1.5: 52 scenarios drive
//! dcrd's real loadConfig with syntax-heavy command lines (short
//! options in separate, concatenated, and `=` forms, double dashes,
//! quoted values, base-zero integers, conversion failures with
//! go-flags' exact marshal error texts), the INI grammar (quoted
//! values, bool forms, field/short-name matching, sections, and the
//! per-line error texts), and the environment variable defaults —
//! compared field for field through the raw-argv entry point.

// Index arithmetic over pinned vector rows.
#![allow(clippy::arithmetic_side_effects)]

use std::collections::BTreeMap;
use std::fs;

use dcroxide_node::config::ConfigEnv;
use dcroxide_node::load_config_from_argv;

mod common;
use common::emit_cfg;

const VECTORS: &str = include_str!("data/flags_vectors.txt");

/// One scenario's parsed input rows.
#[derive(Default)]
struct Scenario {
    name: String,
    args: Vec<String>,
    conf: Vec<String>,
    env: Vec<(String, String)>,
    expect_ok: Option<String>,
    expect_err: Option<String>,
}

#[test]
fn flags_front_end_matches_dcrd() {
    let mut scenarios: BTreeMap<usize, Scenario> = BTreeMap::new();

    for line in VECTORS.lines() {
        let fields: Vec<&str> = line.splitn(4, '|').collect();
        let n: usize = fields[1].parse().unwrap();
        let sc = scenarios.entry(n).or_default();
        match fields[0] {
            "cscen" => sc.name = fields[2].to_string(),
            "carg" => sc
                .args
                .push(line.splitn(3, '|').nth(2).unwrap().to_string()),
            "cfile" => sc
                .conf
                .push(line.splitn(3, '|').nth(2).unwrap().to_string()),
            "cenv" => sc.env.push((fields[2].to_string(), fields[3].to_string())),
            "cok" => sc.expect_ok = Some(line.splitn(3, '|').nth(2).unwrap().to_string()),
            "cerr" => sc.expect_err = Some(line.splitn(3, '|').nth(2).unwrap().to_string()),
            other => panic!("unknown row tag {other}"),
        }
    }
    assert_eq!(scenarios.len(), 52, "unexpected scenario count");

    for (n, sc) in &scenarios {
        // dcrd registers the service options group only on Windows,
        // so this posix-truth rejection scenario does not apply there.
        if cfg!(windows) && sc.name == "service flag not on posix" {
            continue;
        }
        let home_dir = tempfile::tempdir().unwrap();
        let home = home_dir.path().to_string_lossy().into_owned();

        fs::write(home_dir.path().join("dcrd.conf"), sc.conf.join("\n")).unwrap();

        let args: Vec<String> = sc.args.iter().map(|a| a.replace("@HOME@", &home)).collect();
        let env_vars: BTreeMap<String, String> = sc
            .env
            .iter()
            .map(|(k, v)| (k.clone(), v.replace("@HOME@", &home)))
            .collect();

        let getenv = move |name: &str| env_vars.get(name).cloned();
        let env = ConfigEnv {
            default_home_dir: "/dcroxide-nonexistent-default".to_string(),
            lookup_localhost: Box::new(|| Ok(vec!["::1".to_string(), "127.0.0.1".to_string()])),
            interface_by_name: Box::new(|_| None),
            getenv: Box::new(getenv.clone()),
            user_home: Box::new(|_| None),
            rand_bytes: Box::new(|b: &mut [u8]| b.fill(0x42)),
        };

        match load_config_from_argv(&args, &env) {
            Ok((cfg, remaining)) => {
                let expected = sc
                    .expect_ok
                    .as_ref()
                    .unwrap_or_else(|| panic!("scenario {n} {}: expected error", sc.name));
                // A relocated home creates a default config with
                // generated credentials, tokenized like the dump.
                let norm_creds = sc.name == "short appdata";
                let got = emit_cfg(&cfg, &remaining, &home, norm_creds);
                assert_eq!(&got, expected, "scenario {n}: {}", sc.name);
            }
            Err(err) => {
                let expected = sc
                    .expect_err
                    .as_ref()
                    .unwrap_or_else(|| panic!("scenario {n} {}: unexpected error {err}", sc.name));
                let got = err.replace(&home, "@HOME@");
                assert_eq!(&got, expected, "scenario {n}: {}", sc.name);
            }
        }
    }
}

/// The `-s/--service` option parses in both forms on Windows, where
/// dcrd registers the service options group (the posix rejection is
/// pinned by the vector scenarios).
#[cfg(windows)]
#[test]
fn the_service_command_option_parses() {
    for args in [
        vec!["-s".to_string(), "install".to_string()],
        vec!["--service=stop".to_string()],
    ] {
        let home_dir = tempfile::tempdir().unwrap();
        let home = home_dir.path().to_string_lossy().into_owned();
        let mut full_args = vec![format!("--appdata={home}")];
        full_args.extend(args.clone());
        let env = ConfigEnv {
            default_home_dir: "/dcroxide-nonexistent-default".to_string(),
            lookup_localhost: Box::new(|| Ok(vec!["::1".to_string(), "127.0.0.1".to_string()])),
            interface_by_name: Box::new(|_| None),
            getenv: Box::new(|_| None),
            user_home: Box::new(|_| None),
            rand_bytes: Box::new(|b: &mut [u8]| b.fill(0x42)),
        };
        let (cfg, _) = load_config_from_argv(&full_args, &env)
            .unwrap_or_else(|e| panic!("args {args:?}: {e}"));
        let expected = if args[0] == "-s" { "install" } else { "stop" };
        assert_eq!(cfg.service_command, expected, "args {args:?}");
    }
}

/// The rendered help matches go-flags' output for dcrd's option
/// registry byte for byte (`tools/helpgen` regenerates the vector).
#[test]
fn help_text_matches_the_go_flags_vector() {
    let expected = include_str!("data/help_vector.txt");
    let rendered = dcroxide_node::flags::render_help("dcroxide");
    assert_eq!(rendered, expected, "help text must match go-flags");
}
